files.patch:
@@ -781,7 +781,14 @@ acfs_undo_command() {
             --all) all=true; shift ;;
             --list) list_only=true; shift ;;
             --verify) verify_only=true; shift ;;
-            --category) category="$2"; shift 2 ;;
+            --category)
+                if [[ -z "${2:-}" || "$2" == -* ]]; then
+                    log_error "--category requires a value"
+                    return 1
+                fi
+                category="$2"
+                shift 2
+                ;;
             chg_*) change_ids+=("$1"); shift ;;
             *) log_error "Unknown option: $1"; return 1 ;;
         esac

@@ -557,7 +557,14 @@ run_doctor_fix() {
             --dry-run) DOCTOR_FIX_DRY_RUN=true; shift ;;
             --yes) DOCTOR_FIX_YES=true; shift ;;
             --prompt) DOCTOR_FIX_PROMPT=true; shift ;;
-            --only) only_categories="$2"; shift 2 ;;
+            --only)
+                if [[ -z "${2:-}" || "$2" == -* ]]; then
+                    echo "Error: --only requires a category value" >&2
+                    return 1
+                fi
+                only_categories="$2"
+                shift 2
+                ;;
             *) shift ;;
         esac
     done
